sql:
SELECT SUM(attendance_count) AS total_attendance
FROM event_attendance
WHERE booking_id = 'booking_id';

external_knowledge:
Best-rated venues: Refers to venues with a rating score above 9; 
Significant distance: Teams travel more than 50,000 miles to reach the venues;
Listed from the most to the least traveled: Sorted in descending order by the total miles traveled.

sql:
SELECT SUM(mileage) AS total_mileage
FROM team_venue_visits
WHERE venue_id = 5;

SELECT venue_name, total_visits
FROM venues
ORDER BY total_visits DESC;

external_knowledge:
- "grand arenas" refers to the venue names; 
- "warmer by grass than by concrete" means the surface type is grass; 
- "more than a dozen teams" means more than 10 distinct teams have visited the venue; 
- "can hold more than 10,000 souls" refers to the capacity being greater than 10,000; 
- "public praise" refers to the average rating score; 
- "glowing reviews" means the venues are ranked by the average rating score in descending order.

sql:
SELECT venue_name 
FROM venues 
WHERE capacity = (SELECT MAX(capacity) FROM venues);

SELECT venues.venue_name, venue_maintenance.maintenance_type, venue_maintenance.cost 
FROM venues 
JOIN venue_maintenance ON venues.venue_id = venue_maintenance.venue_id;

SELECT venue_id, AVG(rating_score) AS average_rating
FROM venue_ratings
GROUP BY venue_id;

SELECT v.venue_name, tvv.visit_date, tvv.mileage
FROM venues v
LEFT JOIN team_venue_visits tvv ON v.venue_id = tvv.venue_id;
